sql:
SELECT COUNT(harmonic_id)
FROM harmonic_data
WHERE harmonic_number > 5;

SELECT source, AVG(kp) AS average_kp, AVG(kd) AS average_kd, AVG(kw) AS average_kw
FROM harmonic_data
GROUP BY source;

SELECT *
FROM harmonic_data
WHERE harmonic_number = 25;

external_knowledge:
- The term "top-tier teams" refers to the hierarchy levels in the organizational structure, starting from the highest level down to individual members; 
- "Harmonic values" refer to kp, kd, and kw values typically used in electrical engineering for describing harmonic distortion; 
- "Phase angles" are electrical and mechanical phase angles, which are angular differences between the current and voltage in electrical systems; 
- "Cumulative metrics" represent the running sum of harmonic values for each user within their respective team; 
- "Team-averaged metrics" are the average harmonic and phase angle values across all members of a given team.

sql:
SELECT category, frequency, COUNT(*) AS total
FROM harmonic_numbers
GROUP BY category, frequency;

SELECT harmonic_number_id, harmonic_number, category, frequency 
FROM harmonic_numbers 
WHERE category = 'fundamental';

SELECT DISTINCT harmonic_numbers.harmonic_number, harmonic_numbers.frequency
FROM harmonic_numbers
JOIN harmonic_data ON harmonic_numbers.harmonic_number_id = harmonic_data.harmonic_number;

SELECT user_name
FROM users
WHERE user_id NOT IN (
    SELECT user_id 
    FROM access_logs
);
